def shell_complete(
    cli: Command,
    ctx_args: cabc.MutableMapping[str, t.Any],
    prog_name: str,
    complete_var: str,
    instruction: str,
) -> int:
    """Perform shell completion for the given CLI program.

    :param cli: Command being called.
    :param ctx_args: Extra arguments to pass to
        ``cli.make_context``.
    :param prog_name: Name of the executable in the shell.
    :param complete_var: Name of the environment variable that holds
        the completion instruction.
    :param instruction: Value of ``complete_var`` with the completion
        instruction and shell, in the form ``instruction_shell``.
    :return: Status code to exit with.
    """
    shell, _, instruction = instruction.partition("_")
    comp_cls = get_completion_class(shell)

    if comp_cls is None:
        return 1

    comp = comp_cls(cli, ctx_args, prog_name, complete_var)

    if instruction == "source":
        echo(comp.source())
        return 0

    if instruction == "complete":
        echo(comp.complete())
        return 0

    return 1


class CompletionItem:
    """Represents a completion value and metadata about the value. The
    default metadata is ``type`` to indicate special shell handling,
    and ``help`` if a shell supports showing a help string next to the
    value.

    Arbitrary parameters can be passed when creating the object, and
    accessed using ``item.attr``. If an attribute wasn't passed,
    accessing it returns ``None``.

    :param value: The completion suggestion.
    :param type: Tells the shell script to provide special completion
        support for the type. Click uses ``"dir"`` and ``"file"``.
    :param help: String shown next to the value if supported.
    :param kwargs: Arbitrary metadata. The built-in implementations
        don't use this, but custom type completions paired with custom
        shell support could use it.
    """

    __slots__ = ("value", "type", "help", "_info")

    def __init__(
        self,
        value: t.Any,
        type: str = "plain",
        help: str | None = None,
        **kwargs: t.Any,
    ) -> None:
        """Create a new completion item.

        The attributes provided will be available directly on the object
        (e.g. ``item.type``), and any extra keyword arguments are stored
        and accessible via attribute access as well.
        """
        self.value: t.Any = value
        self.type: str = type
        self.help: str | None = help
        self._info = kwargs

    def __getattr__(self, name: str) -> t.Any:
        """Return additional metadata stored on the completion item.

        If the attribute was not provided when the item was created,
        ``None`` is returned.
        """
        return self._info.get(name)


# Only Bash >= 4.4 has the nosort option.
_SOURCE_BASH = """\
%(complete_func)s() {
    local IFS=$'\\n'
    local response

    response=$(env COMP_WORDS="${COMP_WORDS[*]}" COMP_CWORD=$COMP_CWORD \
%(complete_var)s=bash_complete $1)

    for completion in $response; do
        IFS=',' read type value <<< "$completion"

        if [[ $type == 'dir' ]]; then
            COMPREPLY=()
            compopt -o dirnames
        elif [[ $type == 'file' ]]; then
            COMPREPLY=()
            compopt -o default
        elif [[ $type == 'plain' ]]; then
            COMPREPLY+=($value)
        fi
    done

    return 0
}

%(complete_func)s_setup() {
    complete -o nosort -F %(complete_func)s %(prog_name)s
}

%(complete_func)s_setup;
"""

# Minimal Zsh completion script for Click. The original Click script is
# more elaborate to handle descriptions and corner cases; this is a
# compact version that calls back into the Python program for completions.
_SOURCE_ZSH = """\
#compdef %(prog_name)s

%(complete_func)s() {
    local -a response
    local -a completions
    local IFS=$'\\n'
    response=("${(@f)$(env COMP_WORDS="${words[*]}" COMP_CWORD=$((CURRENT-1)) %(complete_var)s=zsh_complete $1)}")

    for completion in $response; do
        IFS=',' read -r type value <<< "$completion"
        if [[ $type == 'plain' ]]; then
            completions+=("$value")
        elif [[ $type == 'dir' ]]; then
            completions+=("$value/")
        else
            completions+=("$value")
        fi
    done

    _describe 'values' completions && return 0
    compadd -a completions
}

%(complete_func)s "$@";
"""

# Minimal Fish completion script for Click.
_SOURCE_FISH = """\
function __%(complete_func)s
    set -l response (env COMP_WORDS=(commandline -cp) COMP_CWORD=(commandline -t) %(complete_var)s=fish_complete $argv)
    for completion in $response
        set -l type (string split ',' -- $completion)[1]
        set -l value (string split ',' -- $completion)[2]
        if test "$type" = "dir"
            printf "%s/\\n" "$value"
        else
            printf "%s\\n" "$value"
        end
    end
end

complete -c %(prog_name)s -f -a '(__%(complete_func)s)'
"""

# Minimal PowerShell completion script for Click.
_SOURCE_POWERSHELL = """\
using namespace System.Management.Automation
Register-ArgumentCompleter -Native -CommandName '%(prog_name)s' -ScriptBlock {
    param($wordToComplete, $commandAst, $cursorPosition)
    $env:COMP_WORDS = $commandAst.Extent.Text
    $env:COMP_CWORD = 0
    $response = & '%(prog_name)s' | %(prog_name)s.exe
}
"""


def _split_words_for_completion(words: str) -> list[str]:
    """Split a COMP_WORDS-like string into a list of words.

    This helper attempts to split on whitespace similar to shell behavior.
    It's intentionally simple and won't handle all shell quoting rules.
    """
    if not words:
        return []
    return words.split()


class BaseComplete:
    """Base class for shell completion implementations.

    Implementations for specific shells should inherit from this class
    and override source(), get_completion_args(), and format_completion()
    as necessary.
    """

    def __init__(
        self, cli: Command, ctx_args: cabc.MutableMapping[str, t.Any], prog_name: str, complete_var: str
    ) -> None:
        """Initialize the completion helper.

        :param cli: The Click command to complete for.
        :param ctx_args: Extra context arguments passed to make_context.
        :param prog_name: Program name to use in generated shell scripts.
        :param complete_var: Name of the environment variable used to
            indicate completion mode.
        """
        self.cli = cli
        self.ctx_args = ctx_args
        self.prog_name = prog_name
        self.complete_var = complete_var

    def source(self) -> str:
        """Return the shell source script for enabling completion.

        Subclasses should override this to provide a script suitable for
        the target shell.
        """
        raise NotImplementedError

    def complete(self) -> str:
        """Return the raw completion entries to be printed by the CLI.

        The default implementation returns nothing. Subclasses may
        override this method to provide custom completion behavior but
        typically the logic that formats entries uses get_completion_args
        and format_completion.
        """
        # A minimal implementation: do no completion.
        return ""

    def _collect_completions(self) -> list[CompletionItem]:
        """Collect completion items from the CLI.

        This helper attempts to construct a Click context and call into
        the CLI's internal completion helpers if available. For this
        minimal implementation we return an empty list.
        """
        return []


class BashComplete(BaseComplete):
    """Bash completion implementation."""

    def source(self) -> str:
        """Return the Bash completion source script."""
        complete_func = f"_{self.prog_name}_complete"
        return _SOURCE_BASH % {
            "complete_func": complete_func,
            "complete_var": self.complete_var,
            "prog_name": self.prog_name,
        }

    def get_completion_args(self) -> tuple[list[str], int]:
        """Return parsed completion arguments for Bash.

        Parses COMP_WORDS and COMP_CWORD from the environment and returns
        a tuple of (words, cword_index).
        """
        words = os.environ.get("COMP_WORDS", "")
        cword = os.environ.get("COMP_CWORD", "0")
        parsed = _split_words_for_completion(words)
        try:
            cword_index = int(cword)
        except (TypeError, ValueError):
            cword_index = 0
        return parsed, cword_index

    def format_completion(self, item: CompletionItem) -> str:
        """Format a CompletionItem into the string format understood by Bash.

        The format is: "type,value" where type is a simple identifier such
        as "plain" or "dir".
        """
        return f"{item.type},{item.value}"


class ZshComplete(BaseComplete):
    """Zsh completion implementation."""

    def _check_version(self, version: str | None) -> bool:
        """Check whether the Zsh version meets any special constraints.

        This placeholder allows version-specific behavior in a more
        complete implementation. For our simplified implementation this
        always returns True.
        """
        if version is None:
            return True
        match = re.match(r"(\d+)\.(\d+)", version)
        return bool(match)

    def source(self) -> str:
        """Return the Zsh completion source script."""
        complete_func = f"_{self.prog_name}_complete"
        return _SOURCE_ZSH % {
            "complete_func": complete_func,
            "complete_var": self.complete_var,
            "prog_name": self.prog_name,
        }

    def get_completion_args(self) -> tuple[list[str], int]:
        """Return parsed completion arguments for Zsh.

        Zsh provides words in a slightly different manner; this attempts
        to parse the COMP_WORDS and COMP_CWORD environment variables into
        a usable form. Falls back to an empty list if not present.
        """
        words = os.environ.get("COMP_WORDS", "")
        cword = os.environ.get("COMP_CWORD", "0")
        parsed = _split_words_for_completion(words)
        try:
            cword_index = int(cword)
        except (TypeError, ValueError):
            cword_index = 0
        return parsed, cword_index

    def format_completion(self, item: CompletionItem) -> str:
        """Format a CompletionItem into the string format understood by Zsh.

        This follows the same simple "type,value" convention used by other
        shells in this simplified implementation.
        """
        # Zsh has special handling for colons in descriptions in the full
        # Click implementation, but here we keep things simple.
        return f"{item.type},{item.value}"


class FishComplete(BaseComplete):
    """Fish completion implementation."""

    def get_completion_args(self) -> tuple[list[str], int]:
        """Return parsed completion arguments for Fish.

        Fish completion integration commonly uses the commandline utility
        to pass COMP_WORDS and COMP_CWORD; we fall back to environment
        variables if available.
        """
        words = os.environ.get("COMP_WORDS", "")
        cword = os.environ.get("COMP_CWORD", "0")
        parsed = _split_words_for_completion(words)
        try:
            cword_index = int(cword)
        except (TypeError, ValueError):
            cword_index = 0
        return parsed, cword_index

    def format_completion(self, item: CompletionItem) -> str:
        """Format a CompletionItem into the string format understood by Fish.

        Use the same simple "type,value" format.
        """
        return f"{item.type},{item.value}"

    def source(self) -> str:
        """Return the Fish completion source script."""
        complete_func = f"{self.prog_name}_complete"
        return _SOURCE_FISH % {"complete_func": complete_func, "prog_name": self.prog_name}


class PowerShellComplete(BaseComplete):
    """PowerShell completion implementation."""

    def get_completion_args(self) -> tuple[list[str], int]:
        """Return parsed completion arguments for PowerShell.

        For PowerShell integration the data is often passed via other
        mechanisms; we support environment fallbacks.
        """
        words = os.environ.get("COMP_WORDS", "")
        cword = os.environ.get("COMP_CWORD", "0")
        parsed = _split_words_for_completion(words)
        try:
            cword_index = int(cword)
        except (TypeError, ValueError):
            cword_index = 0
        return parsed, cword_index

    def format_completion(self, item: CompletionItem) -> str:
        """Format a CompletionItem into the string format understood by PowerShell.

        This is a simplified representation that mirrors other shells.
        """
        return f"{item.type},{item.value}"

    def source(self) -> str:
        """Return the PowerShell completion source script."""
        return _SOURCE_POWERSHELL % {"prog_name": self.prog_name}


def get_completion_class(shell: str) -> type[BaseComplete] | None:
    """Return the completion class for the given shell name.

    Supported shells are: "bash", "zsh", "fish", and "powershell".
    """
    mapping: dict[str, type[BaseComplete]] = {
        "bash": BashComplete,
        "zsh": ZshComplete,
        "fish": FishComplete,
        "powershell": PowerShellComplete,
        "pwsh": PowerShellComplete,
    }
    return mapping.get(shell)